import type { PluginHookRunner } from "openclaw/plugin-sdk";
import { DEFAULT_RESET_TRIGGERS } from "../../../src/config/sessions/types.js";

/**
 * Check if message text is a reset command (/new or /reset)
 */
export function isResetCommand(text: string): boolean {
  const trimmed = text.trim().toLowerCase();
  return DEFAULT_RESET_TRIGGERS.some(trigger => 
    trimmed === trigger || trimmed.startsWith(`${trigger} `)
  );
}

/**
 * Handle reset commands and trigger before_reset hook
 */
export async function handleResetCommand(params: {
  text: string;
  sessionKey: string;
  hookRunner: PluginHookRunner;
  context: Record<string, unknown>;
}): Promise<boolean> {
  const { text, sessionKey, hookRunner, context } = params;

  if (!isResetCommand(text)) {
    return false;
  }

  // Determine action type
  const lowerText = text.trim().toLowerCase();
  const action = lowerText.startsWith('/reset') ? 'reset' : 'new';

  // Trigger before_reset hook
  await hookRunner.runBeforeReset(
    {
      type: 'command',
      action,
      timestamp: Date.now(),
    },
    {
      ...context,
      sessionKey,
    }
  );

  return true;
}

