export async function handleFeishuCommand(
  messageText: string,
  sessionKey: string,
  hookRunner: PluginHookRunner,
  context: {
    cfg: any;
    sessionEntry: any;
    previousSessionEntry?: any;
    commandSource: string;
    timestamp: number;
  }
): Promise<boolean> {
